<script>
import { getSetting, saveSetting } from '@/api/fenzhang'

export default {
  name: 'Fenzhang',
  data () {
    1
    return {
      form: {
        // 是否開啟分帳
        is_open: false,
        // 分帳業務模式 1 平台；2 店鋪
        business_type: '1',
        // 費率
        rate: '0.00',
        // 是否開啟經銷商分帳
        is_open_distributor: false,
        // 代理商戶號，business_type=2時必填
        agent_number: '',
        // 服務器管道號，business_type=2時必填
        provider_number: '',
        // business_type=2時必填
        app_id: ''
      },
      loading: false
    }
  },
  created () {
    this.getDetail()
  },
  methods: {
    // 獲取配置數據
    async getDetail () {
      const res = await getSetting()
      let data = res.data.data
      data.is_open_distributor = data.is_open_distributor == 'true' ? true : false
      data.is_open = data.is_open == 'true' ? true : false
      this.form = JSON.parse(JSON.stringify(data))
    },
    // 費率輸入

    async onSubmit () {
      let { is_open, business_type, rate, is_open_distributor } = this.form
      let params = {
        is_open,
        business_type,
        rate,
        is_open_distributor
      }
      const res = await saveSetting(params)
      this.$message({
        type: 'success',
        message: '儲存成功'
      })
    }
  }
}
</script>

